module div_16bit
(
    input [15:0] A,
    input [7:0] B,
    output [15:0] result,
    output [15:0] odd
);

    reg [15:0] temp_dividend;
    reg [7:0] temp_divisor;
    reg [15:0] temp_quotient;
    reg [15:0] temp_remainder;

    always @(*) begin
        temp_dividend = dividend;
        temp_divisor = divisor;
        temp_quotient = 0;
        temp_remainder = 0;

        if (temp_divisor == 0) begin
            temp_quotient = 16'hFFFF; 
            temp_remainder = temp_dividend; 
        end
        else begin
            while (temp_dividend >= temp_divisor) begin
                temp_dividend = temp_dividend - temp_divisor;
                temp_quotient = {temp_quotient[14:0], 1'b1};
            end
            temp_remainder = temp_dividend;
        end
    end

    assign quotient = temp_quotient;
    assign remainder = temp_remainder;

endmodule
